{
  "family": "Wolff-Kishner Reduction",
  "candidate": {
    "substrate_smiles": [
      "CCC(=O)CCC"
    ],
    "product_smiles": [
      "CCCCCC"
    ],
    "optional_reagent_smiles": [
      "NN",
      "[K+].[OH-]"
    ],
    "rationale": "This is a canonical example of the Wolff-Kishner reduction, showing the deoxygenation of a simple, acyclic, aliphatic ketone (3-hexanone) to its corresponding alkane (n-hexane). The reactants and products are simple, RDKit-parseable, and clearly illustrate the core transformation of C=O to CH2 under basic conditions with hydrazine, which is the hallmark of this reaction.",
    "collision_avoidance_note": "The use of a simple, acyclic, aliphatic ketone avoids aromatic rings (which could trigger Friedel-Crafts or other electrophilic aromatic substitution queries), esters (avoiding Claisen condensation), and other functional groups that might be sensitive to the strongly basic conditions. This specific example is unlikely to be confused with other named reactions like the Clemmensen reduction (acidic conditions) or Mozingo reduction (thiol-based)."
  }
}
